const updateScore = (questionNb, answer, results) => {
    let keysToScore = questionsList[questionNb].score[answer];
    keysToScore.forEach(key => {
        results[key] = results[key] + 1
    } )
    return results
}

const getFinalScore = (questionNb, answer, results) => {
    updateScore(questionNb, answer, results);
    let scores = Object.values(results);
    let highestScore = 0
    //find the highest score in the results object
    scores.forEach(nb => {
        if (nb > highestScore) {
            highestScore = nb
        }
    })
    //find the index matching the highest score in the scores array and then find the matching key in the results object
    return Object.keys(results)[scores.indexOf(highestScore)]
}


export {questionsList}
export {updateScore}
export {getFinalScore}